-- Zone info data migrated from MSSQL ZONE_INFO2369 table
-- 77 zones from the original Knight Online server

CREATE TABLE IF NOT EXISTS zone_info (
    zone_no              SMALLINT     PRIMARY KEY,
    smd_name             VARCHAR(50)  NOT NULL,
    zone_name            VARCHAR(50)  NOT NULL,
    zone_type            SMALLINT     NOT NULL DEFAULT 0,
    min_level            SMALLINT     NOT NULL DEFAULT 1,
    max_level            SMALLINT     NOT NULL DEFAULT 83,
    init_x               INTEGER      NOT NULL DEFAULT 0,
    init_z               INTEGER      NOT NULL DEFAULT 0,
    init_y               INTEGER      NOT NULL DEFAULT 0,
    trade_other_nation   BOOLEAN      NOT NULL DEFAULT FALSE,
    talk_other_nation    BOOLEAN      NOT NULL DEFAULT FALSE,
    attack_other_nation  BOOLEAN      NOT NULL DEFAULT FALSE,
    attack_same_nation   BOOLEAN      NOT NULL DEFAULT FALSE,
    friendly_npc         BOOLEAN      NOT NULL DEFAULT FALSE,
    war_zone             BOOLEAN      NOT NULL DEFAULT FALSE,
    clan_updates         BOOLEAN      NOT NULL DEFAULT FALSE,
    teleport             BOOLEAN      NOT NULL DEFAULT TRUE,
    gate                 BOOLEAN      NOT NULL DEFAULT TRUE,
    escape               BOOLEAN      NOT NULL DEFAULT TRUE,
    calling_friend       BOOLEAN      NOT NULL DEFAULT TRUE,
    teleport_friend      BOOLEAN      NOT NULL DEFAULT TRUE,
    blink                BOOLEAN      NOT NULL DEFAULT TRUE,
    pet_spawn            BOOLEAN      NOT NULL DEFAULT TRUE,
    exp_lost             BOOLEAN      NOT NULL DEFAULT TRUE,
    give_loyalty         BOOLEAN      NOT NULL DEFAULT FALSE,
    guard_summon         BOOLEAN      NOT NULL DEFAULT TRUE,
    military_zone        BOOLEAN      NOT NULL DEFAULT FALSE,
    mining_zone          BOOLEAN      NOT NULL DEFAULT FALSE,
    blink_zone           BOOLEAN      NOT NULL DEFAULT FALSE,
    auto_loot            BOOLEAN      NOT NULL DEFAULT TRUE,
    gold_lose            BOOLEAN      NOT NULL DEFAULT FALSE
);

